// Parse TikTok webhook payload for new comment events
// TikTok sends: video.comment.create events

const body = $input.first().json.body || {};

// TikTok webhook signature verification
// TODO: Add HMAC-SHA256 signature check using TIKTOK_WEBHOOK_SECRET env var
// Header: x-tiktok-signature

// Handle different TikTok webhook payload formats
// Business API format:
if (body.event === 'video.comment.create' || body.type === 'comment') {
  const data = body.data || body;

  return [{
    json: {
      valid: true,
      platform: 'tiktok',
      commentId: data.comment_id || data.id,
      commentText: (data.comment_content || data.text || data.message || '').trim(),
      userId: data.user_openid || data.from_user_id,
      userName: data.user_nickname || data.username || 'TikTok User',
      videoId: data.video_id,
      timestamp: data.create_time || Math.floor(Date.now() / 1000)
    }
  }];
}

// Fallback — unrecognized format
console.warn('[tiktok-parser] Unrecognized webhook payload format:', JSON.stringify(body).substring(0, 200));
return [{ json: { valid: false, reason: 'unrecognized_format', rawBody: body } }];

// Match comment text against keyword rules from environment variable
// Identical matching logic as Instagram — same KEYWORD_RULES env var

const input = $input.first().json;
const commentText = (input.commentText || '').toLowerCase().trim();
const platform = input.platform;

let rules = [];
try {
  rules = JSON.parse(process.env.KEYWORD_RULES || '[]');
} catch (e) {
  console.error('[keyword-matcher] Failed to parse KEYWORD_RULES:', e.message);
  return [{ json: { ...input, hasMatch: false, error: 'rules_parse_error' } }];
}

const now = new Date();
const staticData = $getWorkflowStaticData('global');
const sendCounts = staticData.sendCounts || {};

const activeRules = rules.filter(rule => {
  if (!rule.active) return false;
  if (rule.platform !== platform) return false;
  if (rule.expires_at && new Date(rule.expires_at) < now) return false;
  if (rule.max_dm_sends != null && (sendCounts[rule.id] || 0) >= rule.max_dm_sends) return false;
  return true;
});

let matchedRule = null;
for (const rule of activeRules) {
  const keyword = (rule.keyword || '').toLowerCase().trim();
  const matchType = rule.match_type || 'contains';

  let isMatch = false;
  switch (matchType) {
    case 'exact':
      isMatch = commentText === keyword;
      break;
    case 'starts_with':
      isMatch = commentText.startsWith(keyword);
      break;
    case 'word':
      isMatch = new RegExp('\\b' + keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b').test(commentText);
      break;
    default: // 'contains'
      isMatch = commentText.includes(keyword);
  }

  if (isMatch) {
    matchedRule = rule;
    break;
  }
}

if (!matchedRule) {
  return [{ json: { ...input, hasMatch: false } }];
}

// For TikTok: embed the event link directly in the reply text
// since TikTok DM API is restricted to approved partners
let replyText = matchedRule.public_reply || '';
if (!replyText) {
  // Fallback: use a shortened version of dm_message as the reply
  replyText = `${matchedRule.event_link || ''}`;
}

// Build reply with link
const fullReply = replyText + (matchedRule.event_link && !replyText.includes(matchedRule.event_link)
  ? `\n${matchedRule.event_link}`
  : '');

return [{ json: { ...input, hasMatch: true, matchedRule, replyText: fullReply } }];

// Check cooldown for TikTok replies
// Prevents sending the same reply link to the same user multiple times

const input = $input.first().json;
const { userId, matchedRule, platform } = input;

const staticData = $getWorkflowStaticData('global');
const replyHistory = staticData.replyHistory || {};

const cooldownKey = `${platform}_${userId}_${matchedRule.keyword}`;
const cooldownMs = (matchedRule.cooldown_hours || 720) * 60 * 60 * 1000;
const now = Date.now();
const lastSent = replyHistory[cooldownKey];

const inCooldown = !!(lastSent && (now - lastSent) < cooldownMs);

return [{
  json: {
    ...input,
    shouldReply: !inCooldown,
    cooldownKey,
    inCooldown,
    lastSent: lastSent ? new Date(lastSent).toISOString() : null
  }
}];

// Update analytics and mark reply as sent for cooldown

const data = $('Check Reply Cooldown').first().json;
const { cooldownKey, matchedRule, userId, commentId, commentText, videoId, platform } = data;

const staticData = $getWorkflowStaticData('global');
const now = Date.now();

// Mark reply as sent
if (!staticData.replyHistory) staticData.replyHistory = {};
staticData.replyHistory[cooldownKey] = now;

// Increment send count
if (!staticData.sendCounts) staticData.sendCounts = {};
staticData.sendCounts[matchedRule.id] = (staticData.sendCounts[matchedRule.id] || 0) + 1;

// Analytics
if (!staticData.analytics) staticData.analytics = {};
const analyticsKey = `${platform}_${matchedRule.keyword}`;

if (!staticData.analytics[analyticsKey]) {
  staticData.analytics[analyticsKey] = {
    keyword: matchedRule.keyword,
    platform,
    eventName: matchedRule.event_name || '',
    totalSent: 0,
    firstSent: new Date(now).toISOString(),
    lastSent: null,
    recentSends: []
  };
}

const stats = staticData.analytics[analyticsKey];
stats.totalSent += 1;
stats.lastSent = new Date(now).toISOString();
stats.recentSends.unshift({
  userId,
  commentId,
  videoId,
  commentPreview: (commentText || '').substring(0, 80),
  sentAt: new Date(now).toISOString()
});
stats.recentSends = stats.recentSends.slice(0, 50);

return [{
  json: {
    success: true,
    platform,
    ruleId: matchedRule.id,
    keyword: matchedRule.keyword,
    eventName: matchedRule.event_name,
    userId,
    commentId,
    videoId,
    totalRepliesForKeyword: stats.totalSent,
    sentAt: new Date(now).toISOString()
  }
}];
